COUNTRY_DESCRIPTIONS_HY = {
    "IS": "Իսլանդիան համարվում է աշխարհի ամենաանվտանգ երկրներից մեկը՝ գրեթե զրոյական հանցավորությամբ: Այստեղ ոստիկանները նույնիսկ զենք չեն կրում, իսկ երեխաները ազատ տեղաշարժվում են: Զբոսաշրջիկների համար երկիրը գրավիչ է իր եզակի բնությամբ՝ գեյզերներ, ջրվեժներ, սառցադաշտեր և հրաբուխներ: Այն նաև ԷԿՈ-զբոսաշրջության համաշխարհային կենտրոն է, քանի որ էներգիայի 99%-ը ստացվում է վերականգնվող աղբյուրներից (երկրաջերմային և հիդրոէներգիա):",
    "IE": "Իռլանդիան չափազանց անվտանգ երկիր է՝ բարյացակամ տեղացիներով և ցածր հանցավորության մակարդակով: Այն նաև պատմական հարուստ ժառանգություն ունի՝ ներառյալ դրուիդների ամրոցներ, վիկինգների բնակավայրեր և միջնադարյան տաճարներ: Զբոսաշրջիկների համար առանձնահատուկ հետաքրքիր է փողոցային երաժշտության մշակույթը Դուբլինում, սակայն պետք է զգուշանալ ուժեղ քամիներից Ատլանտյան օվկիանոսի ափին:",
    "NZ": "Նոր Զելանդիան ամենաանվտանգ երկրների եռյակում է՝ բնական գիշատիչների բացակայության (օձեր, մեծ գազաններ) և քաղաքական կայունության շնորհիվ: Այն ԷԿՈ-զբոսաշրջության դրախտ է՝ ֆյորդներով, գեյզերներով, հրաբխային սարահարթերով և կիվի թռչունով: Զբոսաշրջիկները գալիս են այստեղ 'Մատանիների տիրակալի' լանդշաֆտները տեսնելու, սակայն պետք է հաշվի առնել, որ երկիրը շատ հեռու է և թանկ:",
    "AT": "Ավստրիան Եվրոպայի ամենաանվտանգ պետություններից է՝ շնորհիվ սոցիալական բարձր պաշտպանվածության և ոստիկանության արդյունավետ աշխատանքի: Այն գրավում է զբոսաշրջիկներին Ալպերով, դասական երաժշտությամբ (Մոցարտ, Շտրաուս) և մաքուր լճերով: Զբոսաշրջիկների համար խորհուրդ է տրվում այցելել Հոֆբուրգ պալատ և Շյոնբրուն, սակայն պետք է հիշել, որ ձմռանը դահուկային լանջերը վտանգավոր են առանց ուղեցույցի:",
    "CH": "Շվեյցարիան աշխարհի ամենաչեզոք և անվտանգ երկիրն է՝ զենքի ցածր տարածմամբ և բարձր կարգապահությամբ: Այն հայտնի է իր Ալպերով, լճերով (Ժնև, Ցյուրիխ) և ճշգրիտ ժամացույցներով: Զբոսաշրջիկների համար երկիրը թանկ է, սակայն առաջարկում է անվճար հասարակական տրանսպորտ զբոսաշրջային քարտերով: Պետք է զգուշանալ բարձր գներից և չխախտել տեղական հանգստի ժամերը (կիրակի օրերին աղմուկ չի թույլատրվում):",
    "SG": "Սինգապուրը հաճախ ճանաչվում է որպես աշխարհի ամենաանվտանգ երկիր՝ խիստ օրենքների և մահապատժի շնորհիվ թմրանյութերի համար: Այստեղ հանցավորությունը գրեթե բացակայում է, իսկ փողոցները մաքուր են 24/7: Զբոսաշրջիկները գալիս են այստեղ ապագա քաղաքը տեսնելու (Gardens by the Bay, Marina Bay Sands), սակայն պետք է իմանան, որ մաստակը ներմուծելը արգելված է, իսկ աղբ նետելու համար տուգանքը 1000 SGD է:",
    "PT": "Պորտուգալիան համարվում է աշխարհի ամենաանվտանգ երկրներից մեկը՝ ցածր հանցավորությամբ և հյուրընկալ մարդկանցով: Այն հայտնի է իր ԳԱՍՏՐՈՆՈՄԻԱՅՈՎ՝ բակալայաու (աղացած ձողաձուկ) 365 եղանակով, պորտվեյնով և պաստել դե նատայով (կրեմով կարկանդակ): Զբոսաշրջիկների համար առանձնահատուկ հետաքրքիր են Լիսաբոնի յոթ բլուրները և Ալգավրի լողափերը, սակայն պետք է զգուշանալ գրպանահատներից զբոսաշրջային գոտիներում, չնայած դա հազվադեպ է:",
    "DK": "Դանիան սոցիալապես կայուն և ամենաքիչ կոռումպացված երկիրն է աշխարհում՝ հանցավորության ամենացածր մակարդակով: Այն հայտնի է 'hygge' մշակույթով (հարմարավետություն), վիկինգների պատմությամբ և ժամանակակից դիզայնով: Զբոսաշրջիկների համար Կոպենհագենի հեծանվային ուղիները իդեալական են, սակայն պետք է հիշել, որ ալկոհոլը թանկ է, իսկ եղանակը անկանխատեսելի (արև, անձրև, քամի միաժամանակ):",
    "SI": "Սլովենիան Եվրոպայի թաքնված գոհարն է՝ անվտանգության ամենաբարձր ցուցանիշներով և աղտոտվածության ամենացածր մակարդակով: Այն ԷԿՈ-զբոսաշրջության համար իդեալական է՝ շնորհիվ իր անտառների (երկրի 60%-ը), Բլեդի լճի և Տրիգլավ ազգային պարկի: Զբոսաշրջիկներին խորհուրդ է տրվում այցելել Պոստոյնայի քարանձավները, սակայն պետք է զգուշանալ վայրի արջերից, որոնք հանդիպում են անտառներում:",
    "FI": "Ֆինլանդիան արդեն 6-րդ տարին անընդմեջ ճանաչվել է աշխարհի ամենաերջանիկ երկիր, և այն նաև ամենաանվտանգներից է: Այստեղ գրեթե չկա կոռուպցիա, իսկ ոստիկանությունը վայելում է բնակչության լիակատար վստահությունը: Զբոսաշրջիկները գալիս են տեսնելու հազարավոր լճերը, հյուսիսափայլը և Ձմեռ պապին Ռովանիեմիում, սակայն ձմռանը պետք է զգուշանալ -30°C ցրտից և մետաղական առարկաները լիզելուց:",

    "AF": "Աֆղանստանը ներկայումս աշխարհի ամենավտանգավոր երկիրն է՝ թալիբների վարչակարգի պատճառով (2021-ից): Այստեղ ահաբեկչական հարձակումները, առևանգումներն ու ռմբակոծությունները ամենօրյա երևույթ են: Զբոսաշրջության համար երկիրը խստիվ արգելվում է, քանի որ օտարերկրացիները թիրախավորվում են փրկագնի կամ քաղաքական նպատակներով: Նույնիսկ դեսպանատները խորհուրդ են տալիս անհապաղ լքել երկիրը:",
    "YE": "Եմենը 2014 թվականից գտնվում է քաղաքացիական պատերազմի մեջ, որը խլել է ավելի քան 150,000 մարդու կյանք: Այստեղ գործում են հուսի ապստամբները, Ալ-Կաիդան և իսլամական պետությունը, իսկ Սաուդյան Արաբիայի գլխավորած կոալիցիան անընդհատ ռմբակոծում է քաղաքները: Զբոսաշրջիկները չեն կարող մուտք գործել երկիր, քանի որ նույնիսկ Սանաայի օդանավակայանը փակ է: Բացի դրանից, երկրում սով է և խոլերայի համաճարակ:",
    "SY": "Սիրիայում 2011 թվականից շարունակվում է ավերիչ քաղաքացիական պատերազմ, որի հետևանքով ավերվել է երկրի 70%-ը: Այստեղ օգտագործվել է քիմիական զենք, ԻՊ-ի ահաբեկիչները պահպանում են քնած բջիջներ, իսկ ռուսական և թուրքական ուժերը մարտնչում են տարբեր կողմերում: Զբոսաշրջությունը գոյություն չունի. յուրաքանչյուր օտարերկրացի ռիսկի է դիմում առևանգվելու կամ սպանվելու:",
    "LY": "Լիբիան 2014 թվականից ի վեր չունի կենտրոնական կառավարություն. երկիրը բաժանված է միլիցիաների, ցեղերի և կառավարությունների միջև (Արևելք vs Արևմուտք): Այստեղ ծաղկում է մարդկանց թրաֆիքինգը, ստրկավաճառությունը և առևանգումները փրկագնի դիմաց: Զբոսաշրջիկների համար չափազանց վտանգավոր է. 2023-ին մի քանի եվրոպացի զբոսաշրջիկներ առևանգվել են և ազատ արձակվել միայն ահռելի փրկագնից հետո:",
    "SO": "Սոմալին 1991 թվականից ի վեր գտնվում է անարխիայի մեջ, հայտնի է ծովահեններով և Ալ-Շաբաբ ահաբեկչական խմբավորմամբ: Այստեղ ամեն օր պայթյուններ են որոտում Մոգադիշոյում, իսկ միջազգային նավերը հարձակման են ենթարկվում Ադենի ծոցում: Զբոսաշրջության համար երկիրն անհնար է. նույնիսկ ՄԱԿ-ի աշխատակիցները շարժվում են զրահամեքենաներով:",
    "SD": "Սուդանում 2023 թվականի ապրիլին սկսվեց արյունալի քաղաքացիական պատերազմ բանակի (SAF) և արագ արձագանքման ուժերի (RSF) միջև: Այս պատերազմում զոհվել է ավելի քան 10,000 մարդ, իսկ Դարֆուրում սկսվել է ցեղասպանություն: Զբոսաշրջիկները չեն կարող մուտք գործել, քանի որ Խարտումը ավերված է, օդանավակայանները փակ են, իսկ սննդի և ջրի պակաս կա:",
    "SS": "Հարավային Սուդանը աշխարհի ամենաերիտասարդ (2011-ից) և ամենավտանգավոր երկիրն է՝ ցեղային պատերազմների պատճառով: Այստեղ 60 էթնիկ խմբեր միմյանց դեմ են լարազենքերով, տարածված է կանիբալիզմը (մարդակերությունը) որոշ ցեղերում, իսկ ՄԱԿ-ի խաղաղապահները չեն կարողանում վերահսկել իրավիճակը: Զբոսաշրջիկների համար երկիրն ամբողջությամբ փակ է, քանի որ առևանգումները սովորական են:",
    "HT": "Հայիթին ամենաաղքատ երկիրն է Ամերիկաներում, որտեղ 2021 թվականից բանդիտները վերահսկում են մայրաքաղաք Պորտ-օ-Պրենսի 80%-ը: Առևանգումները (այդ թվում՝ ամերիկացի քահանաների) ամենօրյա են, իսկ տեղական ոստիկանությունը անզոր է: Զբոսաշրջիկները խստիվ զգուշացվում են չայցելել երկիր, քանի որ դեսպանությունները փակել են իրենց դռները, իսկ օդանավակայանը հաճախ է ենթարկվում կրակոցների:",
    "UA": "Ուկրաինան 2022 թվականի փետրվարի 24-ից գտնվում է լայնամասշտաբ պատերազմի մեջ Ռուսաստանի դեմ: Ամեն օր ռմբակոծվում են քաղաքներ, ականապատված են դաշտերը, մարտական գործողություններ են ընթանում Դոնբասում, Խարկովի և Զապորոժիեի մարզերում: Զբոսաշրջությունը թույլատրվում է միայն Լվովի նման հեռավոր արևմտյան շրջաններում, սակայն օդային տագնապները ամենօրյա են, իսկ պարետային ժամը գիշերը:",
    "MM": "Մյանմայում (Բիրմա) 2021 թվականի փետրվարի 1-ի ռազմական հեղաշրջումից հետո սկսվել է քաղաքացիական պատերազմ: Այստեղ ռազմական խունտան բանտարկում է ցուցարարներին, արևմտյան երկրները պատժամիջոցներ են սահմանել, իսկ էթնիկ զինված խմբերը (Kachin, Karen, Rohingya) կռվում են անկախության համար: Զբոսաշրջիկները վտանգում են ազատազրկում ստանալ, եթե նույնիսկ քննադատեն ռեժիմը սոցցանցերում:",

    "CR": "Կոստա Ռիկան համարվում է ԷԿՈ-զբոսաշրջության համաշխարհային առաջատարը, քանի որ երկրի 25%-ը պահպանվող տարածքներ են: Այստեղ զբոսաշրջիկները կարող են տեսնել 5% համաշխարհային կենսաբազմազանությունը (վահանագորտեր, ծովային կրիաներ, թութակներ) արևադարձային անտառներում: Երկիրը արտադրում է իր էլեկտրաէներգիայի 98%-ը վերականգնվող աղբյուրներից (հիդրո, հողմ, արև, երկրաջերմային): Զբոսաշրջիկներին խորհուրդ է տրվում այցելել Monteverde ամպային անտառ և Tortuguero ջրանցքներ, սակայն պետք է զգուշանալ թունավոր օձերից:",
    "NO": "Նորվեգիան ԷԿՈ-դրախտ է՝ շնորհիվ իր ֆյորդերի (Գեյրանգեր, Ներիոյ), լեռների և մաքուր օդի: Երկիրն աշխարհում առաջատարն է էլեկտրոմոբիլների քանակով (ավելի քան 80% նոր վաճառվող մեքենաների) և հիդրոէներգիայի օգտագործմամբ (99%): Զբոսաշրջիկների համար առանձնահատուկ հետաքրքիր է 'Norway in a Nutshell' երթուղին (գնացք, նավակ, ավտոբուս), սակայն պետք է հաշվի առնել, որ երկիրը շատ թանկ է (մեկ գարեջուրը արժե 10-12 եվրո):",
    "EC": "Էկվադորը հայտնի է Գալապագոսյան կղզիներով, որտեղ Չարլզ Դարվինը մշակեց էվոլյուցիայի տեսությունը: Այստեղ կենդանիները չեն վախենում մարդկանցից (հսկա կրիաներ, ծովային իգուանաներ, կապույտոտանի ջայլամներ), իսկ կղզիները խիստ պահպանվում են: Էկվադորը նաև Ամազոնի անձրևային անտառների դարպասն է. զբոսաշրջիկները կարող են գիշերել էկո-լոջաներում և դիտել հարյուրավոր թռչուններ: Պետք է նշել, որ Գալապագոս այցելելու համար պահանջվում է հատուկ թույլտվություն (100 ԱՄՆ դոլար):",
    "CL": "Չիլին ձգվում է 4300 կմ հյուսիսից հարավ, ներառելով աշխարհի ամենաչոր անապատը (Ատակամա) և Պատագոնիայի սառցադաշտերը: Այստեղ գտնվում են աշխարհի ամենամաքուր երկինքները (ALMA աստղադիտարան), ինչը գրավում է աստղագետներին: Զբոսաշրջիկների համար ԷԿՈ-ակտիվությունները ներառում են հրաբուխներ մագլցել, տորդել դաշտերում զբոսնել և պինգվիններ դիտել: Պետք է հիշել, որ հարավում եղանակը շատ փոփոխական է, իսկ քամիները կարող են հասնել 100 կմ/ժ արագության:",
    "PE": "Պերուն համատեղում է պատմությունը (Մաչու Պիկչու) և էկոլոգիան (Ամազոն): Երկրի 60%-ը ծածկված է արևադարձային անտառներով, որտեղ ապրում են հազարավոր թռչուններ, կապիկներ, յագուարներ և անակոնդաներ: Զբոսաշրջիկները կարող են այցելել Տամբոպատա ազգային արգելոցը, որտեղ գործում են էկո-լոջաներ (առանց էլեկտրականության, արևային վահանակներով): Մաչու Պիկչու գնալու համար պետք է ամրագրել ամիսներ առաջ, քանի որ օրական թույլատրվում է միայն 2500 այցելու:",
    "PW": "Պալաուն (PW) խաղաղօվկիանոսյան կղզի-պետություն է, որը ստեղծել է աշխարհի առաջին շնաձկների ապաստարանը (2009) և արգելել է ռեֆերին վնասող արևապաշտպան քսուքները: Այստեղ գտնվում է Մեդուզաների լիճը, որտեղ միլիոնավոր մեդուզաներ (անվնաս) լողում են արևի հետևից: Պալաուն ունի ծովային արգելոց, որտեղ ձկնորսությունն արգելված է ամբողջ տարածքի 80%-ում. զբոսաշրջիկները կարող են սուզվել կորալային խութերում և տեսնել մանտա ճառագայթներին:",
    "KE": "Քենիան հայտնի է սավաննաներով և 'Մեծ հինգ' կենդանիներով (առյուծ, փիղ, ռնգեղջյուր, լեոպարդ, գոմեշ): Ամեն տարի հուլիս-հոկտեմբերին տեղի է ունենում վայրի կենդանիների մեծագույն միգրացիան Մասայ Մարայում (1.5 միլիոն կեղտոտ գնուներ): Զբոսաշրջիկների համար գործում են էկո-ճամբարներ, որոնք աշխատում են արևային էներգիայով և ջուրը մաքրում են տեղում: Պետք է զգուշանալ մալարիայից (պարտադիր են հակամալարիային դեղահաբերը) և չմոտենալ կենդանիներին 10 մետրից ավելի մոտ:",

    "IT": "Իտալիան համաշխարհային խոհանոցի թագուհին է, որտեղ ամեն տարածաշրջան ունի իր սեփական ավանդույթները: Պիցցան ծնվել է Նեապոլում (Marinara, Margherita), իսկ պաստան (սպագետտի, ֆետուչինե, պեննե) ունի հարյուրավոր տեսակներ: Զբոսաշրջիկները պետք է փորձեն ռիզոտտոն Միլանում, լազանյան Բոլոնիայում, ջելատոն (պաղպաղակ) Ֆլորենցիայում և տիրամիսուն Վենետիկում: Կարևոր է իմանալ, որ իտալացիները կապուչինո խմում են միայն նախաճաշին (մինչև 11:00), իսկ պիցցայի վրա արքայախնձոր ավելացնելը համարվում է սրբապղծություն:",
    "TH": "Թաիլանդը հայտնի է իր փողոցային սննդով, որը 2017-2023 թվականներին ճանաչվել է աշխարհի լավագույնը: Այստեղ պետք է փորձել Տոմ Յում ապուրը (կծու թթու ծովամթերքով), Պադ Թաի (տապակած արիշտա), Կանաչ կարրին (կոկոսի կաթով), Սոմ Տամ (պապայայի աղցան) և Մանգո կպչուն բրինձը (աղանդեր): Զբոսաշրջիկները պետք է զգույշ լինեն, քանի որ թաիլանդական ուտեստները չափազանց կծու են (կարելի է ասել 'mai pet' - ոչ կծու): Նաև պետք է հիշել, որ փողոցային սնունդը անվտանգ է, բայց մի խմեք ծորակի ջուր:",
    "JP": "Ճապոնիան ունի աշխարհի ամենաշատ Միշլեն աստղ ունեցող ռեստորանները (ավելի քան 400): Այստեղ սուշին և սաշիմին արվեստ են, որտեղ թարմությունը գերագույն արժեք է: Զբոսաշրջիկները պետք է փորձեն ռամեն (արիշտա արգանակով), տեմպուրա (խորը տապակած ծովամթերք), տակոյակի (ութոտնուկով գնդիկներ), վագյու (ճապոնական մարմարյա տավարի միս) և մոչի (բրնձով քաղցրավենիք): Կարևոր է իմանալ, որ Ճապոնիայում ընդունված է բարձրաձայն ձայնով ուտել արիշտան (ցույց տալով, որ համեղ է), և երբեք չպետք է ձողիկները ծակել բրնձի մեջ (դա հուղարկավորության ծես է):",
    "ES": "Իսպանիան հայտնի է տապասով (փոքր չափաբաժիններով ուտեստներ), որը կարելի է պատվիրել ցանկացած բարում: Պաելյան ծնվել է Վալենսիայում (բրինձ ծովամթերքով կամ հավով), իսկ խամոն սերրանոն (բուժված խոզապուխտ) համարվում է դելիկատես: Զբոսաշրջիկները պետք է փորձեն գազպաչո (սառը լոլիկի ապուր), չուրոս (տապակած խմորեղեն շոկոլադով), և տորտիլյա դե պատատաս (կարտոֆիլով ձվածեղ): Պետք է հիշել, որ իսպանացիները ճաշում են 14:00-16:00, ընթրում են 21:00-23:00, իսկ սիեստայի ժամանակ (14:00-17:00) շատ խանութներ փակ են:",
    "FR": "Ֆրանսիան համարվում է նրբաճաշակ խոհանոցի մայրաքաղաքը, որտեղ ՅՈՒՆԵՍԿՕ-ն ճանաչել է ֆրանսիական խոհանոցը որպես ոչ նյութական մշակութային ժառանգություն: Այստեղ պետք է փորձել էսկարգո (խխունջներ սխտորի կարագով), ֆուա գրա (բադի լյարդ), կրուասան, մակարոն, և ավելի քան 400 տեսակի պանիր (Կամամբեր, Ռոքֆոր, Բրի): Զբոսաշրջիկները պետք է իմանան, որ լավագույն ռեստորաններում հագուստի կոդ կա (պիտի կրել բաճկոն), և որ խորհուրդ չի տրվում ավելացնել սառույց կարմիր գինուն:",
    "MX": "Մեքսիկական խոհանոցը ՅՈՒՆԵՍԿՕ-ի ժառանգություն է, որը հայտնի է իր պիկանտությամբ և գույներով: Տակոն (եղջերուի միս, արքայախնձոր, կիլանտրո), էնչիլադան (տորտիլլա սոուսով), և գուակամոլեն (ավոկադոյի մածուկ) ամենահայտնի ուտեստներն են: Զբոսաշրջիկները պետք է փորձեն նաև մոլե (կակաոյի սոուսով հավ), չիլի էն նոգադա (լցոնված չիլի ընկույզի սոուսով) և տեկիլան (ագավայից): Պետք է զգուշանալ 'Մոնտեսումայի վրեժից' (ստամոքսի խանգարում) և մի խմել ծորակի ջուր, միայն շշալցված:",
    "PT": "Պորտուգալիան ձկնային խոհանոցի երկիր է, որտեղ բակալայաուն (աղացած ձողաձուկ) ունի 365 բաղադրատոմս (տարվա ամեն օրվա համար): Ազգային ուտեստը 'pastel de nata'-ն է (կրեմով կարկանդակ), որը պետք է ուտել տաք վիճակում դարչինով: Զբոսաշրջիկները պետք է փորձեն նաև գրիլից սարդինաներ (հունիսին փառատոն է), պորտվեյն (Դուրո հովտից) և 'caldo verde' (կանաչ ապուր երշիկով): Պետք է հիշել, որ պորտուգալացիները շատ հպարտ են իրենց բակալայաուով, և երբեք մի ասեք, որ այն նման է ձողաձկան այլ տեսակների:",
    "VN": "Վիետնամը հայտնի է իր թարմ, կանաչ խոհանոցով, որտեղ համեմունքները մատուցվում են առանձին: Ֆոն (բրնձի արիշտա արգանակով տավարի մսով) համարվում է ազգային ուտեստ, որը ուտում են նախաճաշին: Զբոսաշրջիկները պետք է փորձեն բան մի (ֆրանսիական բագետ վիետնամական միջուկով), գարնանային ռուլետ (թարմ կամ տապակած), և վիետնամական սուրճ (կոնդենսացված կաթով, շատ ուժեղ): Պետք է իմանալ, որ հյուսիսում (Հանոյ) ֆոն ավելի աղի է, իսկ հարավում (Սայգոն)՝ ավելի քաղցր:",
    "BR": "Բրազիլիան չուրասկոյի (մսի խորոված) երկիր է, որտեղ մատուցողները շրջում են մեծ շամփուրներով և կտրում միսը ձեր ափսեի մեջ: Ազգային ուտեստը ֆեյժոադան է (սև լոբի տարբեր մսի տեսակներով), որը պատմականորեն ստրուկների սնունդ էր: Զբոսաշրջիկները պետք է խմեն կայպիրինյա (կոկտեյլ կախասայով, լայմով և շաքարով) և փորձեն պան դե քեյջո (պանրով փքաբլիթ): Պետք է հիշել, որ բրազիլական խորովածը անսահմանափակ է (rodízio), բայց թանկ արժե (40-60 ԱՄՆ դոլար):",

    "EG": "Եգիպտոսը 5000 տարվա պատմություն ունի, և նրա բուրգերը աշխարհի յոթ հրաշալիքներից միակն են, որ պահպանվել են: Գիզայի բուրգերը (Քեոփսի, Խաֆրեի, Մենկաուրեի) կառուցվել են մ.թ.ա. 2560-2540 թվականներին, և դրանք պարունակում են 2.3 միլիոն քարե բլոկ: Զբոսաշրջիկները պետք է այցելեն նաև Սֆինքսին, Լուքսորի տաճարներին, Թութանհամոնի գերեզմանին (Թագավորների հովիտ) և Ասուանի ամբարտակին: Պետք է զգուշանալ, որ ամռանը ջերմաստիճանը հասնում է 45°C-ի, իսկ տեղացի վաճառողները շատ համառ են:",
    "GR": "Հունաստանը համարվում է Արևմտյան քաղաքակրթության օրրանը, որտեղ ծնվել են ժողովրդավարությունը, փիլիսոփայությունը (Սոկրատես, Պլատոն, Արիստոտել), թատրոնը և Օլիմպիական խաղերը: Աթենքի Ակրոպոլիսը (Պարթենոն) կառուցվել է մ.թ.ա. 447-438 թվականներին՝ ի պատիվ Աթենաս աստվածուհու: Զբոսաշրջիկները պետք է տեսնեն Դելֆին (Ապոլոնի տաճար), Օլիմպիան (առաջին Օլիմպիական խաղերի վայրը), և Սանտորինիի կղզին (հրաբխային): Պետք է հիշել, որ ամռանը շոգ է, իսկ հնավայրերը լեփ-լեցուն են:",
    "CN": "Չինաստանն ունի 5000-ամյա գրավոր պատմություն, որտեղ կառուցվել են Չինական Մեծ պարիսպը (մ.թ.ա. 7-րդ դար, 21,196 կմ երկարություն) և Արգելված քաղաքը (1420, 980 շենք): 1974 թվականին Շի Հուանգդիի դամբարանում հայտնաբերվել են 8000 տեռակոտա մարտիկներ (մ.թ.ա. 210): Զբոսաշրջիկները պետք է այցելեն նաև Լեռնային տաճարներ (ՅՈՒՆԵՍԿՕ), Շանհայի աշտարակը (632 մ) և Գիլինի կարստային լեռները: Պետք է իմանալ, որ երկրում արգելված են Facebook, Google, և պետք է հարգել տեղական օրենքները:",
    "GB": "Մեծ Բրիտանիան ունի 2000-ամյա պատմություն՝ հռոմեական օկուպացիայից մինչև արդյունաբերական հեղափոխություն: Լոնդոնի Թաուերը (1066) եղել է բանտ, գանձարան և կենդանաբանական այգի, իսկ Բուքինգհեմյան պալատը թագավորական նստավայր է: Զբոսաշրջիկները պետք է այցելեն Սթոունհենջը (մ.թ.ա. 2500, նեոլիթյան հուշարձան), Էդինբուրգի ամրոցը, Բաթի հռոմեական լոգանքները և Օքսֆորդի համալսարանը (1096): Պետք է հիշել, որ Շոտլանդիան, Ուելսը և Հյուսիսային Իռլանդիան ունեն իրենց սեփական օրենքները:",
    "GE": "Վրաստանը հնագույն քրիստոնեական երկիր է, որը քրիստոնեությունը ընդունել է 326 թվականին (հայերից 25 տարի հետո): Այստեղ գտնվում են Սվետիցխովելի տաճարը (1010, որտեղ պահվում է Քրիստոսի զգեստը), Ջվարի վանքը (590-604) և Ուփլիսցիխե քարանձավային քաղաքը (մ.թ.ա. 1-ին հազարամյակ): Զբոսաշրջիկները պետք է տեսնեն Սվանեթի աշտարակները (միջնադարյան պաշտպանական), Վարդզիա (12-րդ դարի քարանձավային համալիր) և Թբիլիսիի հին քաղաքը: Պետք է հարգել վրացական եկեղեցիները (կանայք պետք է կրեն շարֆ):",
    "IN": "Հնդկաստանը Հարավային Ասիայի ամենահին քաղաքակրթությունն է (Հարապպա, Մոհենջո Դարո, մ.թ.ա. 2600): Տաջ Մահալը (1632-1653) կառուցվել է մողոլ կայսր Շահ Ջահանի կողմից ի հիշատակ իր կնոջ՝ այն համարվում է մահմեդական արվեստի գոհարը: Զբոսաշրջիկները պետք է տեսնեն Կարմիր ամրոցը (Դելի), Էլլորա և Աջանտա քարանձավները (բուդդայական, հինդուական, ջայնիստական տաճարներ), և Վարանասի քաղաքը (հինդուների սուրբ քաղաք): Պետք է զգուշանալ մոնտեզումայի վրեժից (մի խմել ծորակի ջուր):",
}